const response = $input.first().json;
let text = response.content.parts[0].text;
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(text);

const chars = data.characters;
let charList = '';
let jsonFormat = '{\n';

for (let i = 0; i < chars.length; i++) {
  charList += 'Character ' + (i + 1) + ': ' + chars[i].name + ' — ' + chars[i].description + '\n\n';
  if (i < chars.length - 1) {
    jsonFormat += '  "character_' + (i + 1) + '_prompt": "...",\n';
  } else {
    jsonFormat += '  "character_' + (i + 1) + '_prompt": "..."\n';
  }
}

jsonFormat += '}';

return chars.map((char, i) => ({
  json: {
    character_index: i + 1,
    character_name: char.name,
    character_desc: char.description,
    character_count: chars.length
  }
}));

const items = $input.all();

let charList = '';
let jsonFormat = '{\n';

for (let i = 0; i < items.length; i++) {
  const c = items[i].json;
  charList += 'Character ' + c.character_index + ': ' + c.character_name + ' — ' + c.character_desc + '\n\n';
  if (i < items.length - 1) {
    jsonFormat += '  "character_' + c.character_index + '_prompt": "...",\n';
  } else {
    jsonFormat += '  "character_' + c.character_index + '_prompt": "..."\n';
  }
}

jsonFormat += '}';

return [{
  json: {
    character_count: items.length,
    character_list: charList,
    json_format: jsonFormat
  }
}];

const prompts = $input.first().json.output.prompts;

return prompts.map(p => ({
  json: {
    character_index: p.character_index,
    character_name: p.character_name,
    prompt: p.prompt
  }
}));

const items = $input.all();
const base64 = $('Extract from File').first().json.data;

return items.map(item => ({
  json: {
    character_index: item.json.character_index,
    character_name: item.json.character_name,
    payload: {
      contents: [
        {
          parts: [
            { text: item.json.prompt },
            {
              inline_data: {
                mime_type: "image/png",
                data: base64
              }
            }
          ]
        }
      ],
      generationConfig: {
        responseModalities: ["TEXT", "IMAGE"],
        imageConfig: {
          aspectRatio: "16:9",
          imageSize: "1K"
        }
      }
    }
  }
}));

const cloudinary = $input.all();
const characters = $('Parse Characters').all(); // change to your code node name that has character_name

return cloudinary.map((item, i) => ({
  json: {
    character_index: i + 1,
    character_name: characters[i].json.character_name,
    character_image_url: item.json.secure_url
  }
}));

const items = $input.all();

let charList = '';
let charMap = [];

for (const item of items) {
  const c = item.json;
  charList += c.character_name + ' (image: ' + c.character_image_url + ')\n';
  charMap.push({
    character_index: c.character_index,
    character_name: c.character_name,
    character_image_url: c.character_image_url
  });
}

return [{
  json: {
    character_count: items.length,
    character_list: charList,
    character_map: charMap
  }
}];

const story = $input.first().json.output;
const charMap = $('Map Character URLs').all(); // change to your node name with character URLs

return story.chunks.map(chunk => ({
  json: {
    title: story.title,
    chunk_number: chunk.chunk_number,
    script: chunk.script,
    image_prompt: chunk.image_prompt,
    duration_seconds: chunk.duration_seconds,
    characters_used: chunk.characters_used,
    character_images: chunk.characters_used.map(i => 
      charMap[i - 1].json.character_image_url
    )
  }
}));

const chunks = $input.all();
const allUrls = new Set();

for (const chunk of chunks) {
  for (const url of chunk.json.character_images) {
    allUrls.add(url);
  }
}

return [...allUrls].map((url, i) => ({
  json: {
    character_index: i + 1,
    image_url: url
  }
}));

const story = $('Generate Story').first().json.output;
const charUrls = $('Extract Unique Character URLs').all();

const characters = charUrls.map(c => ({
  character_index: c.json.character_index,
  image_url: c.json.image_url
}));

const chunks = story.chunks.map(chunk => ({
  chunk_number: chunk.chunk_number,
  script: chunk.script,
  image_prompt: chunk.image_prompt,
  duration_seconds: chunk.duration_seconds,
  characters_used: chunk.characters_used,
  character_images: chunk.characters_used.map(i =>
    characters.find(c => c.character_index === i).image_url
  )
}));

return [{
  json: {
    title: story.title,
    characters: characters,
    chunks: chunks
  }
}];

