    chunk_number: chunk.chunk_number,
    script: chunk.script,
    image_prompt: chunk.image_prompt,
    duration_seconds: chunk.duration_seconds,
    characters_used: chunk.characters_used,
    character_images: chunk.character_images
  }
}));

const body = $('Webhook').first().json.body;

return body.characters.map(c => ({
  json: {
    character_index: c.character_index,
    image_url: c.image_url
  }
}));

const items = $input.all();

return [{
  json: {
    character_base64: items.map((item, i) => ({
      character_index: i + 1,
      base64: item.json.data,
      mimetype: item.json.mimetype || 'image/jpeg'
    }))
  }
}];

const charData = $('Build Base64 Map').first().json.character_base64;
const body = $('Webhook').first().json.body;

return body.chunks.map(chunk => {
  const parts = [
    { text: chunk.image_prompt }
  ];

  for (const charIdx of chunk.characters_used) {
    const char = charData.find(c => c.character_index === charIdx);
    if (char) {
      parts.push({
        inline_data: {
          mime_type: char.mimetype,
          data: char.base64
        }
      });
    }
  }

  return {
    json: {
      chunk_number: chunk.chunk_number,
      script: chunk.script,
      duration_seconds: chunk.duration_seconds,
      payload: {
        contents: [{ parts }],
        generationConfig: {
          responseModalities: ["TEXT", "IMAGE"],
          imageConfig: {
            aspectRatio: "16:9",
            imageSize: "1K"
          }
        }
      }
    }
  };
});

