const scenes = $input.first().json.output.scenes;
const body = $('Webhook1').first().json.body;

return scenes.map((scene, i) => ({
  json: {
    chunk_number: scene.chunk_number,
    script: body.chunks[i].script,
    duration_seconds: body.chunks[i].duration_seconds,
    scene_image_url: body.chunks[i].scene_image_url,
    video_prompt: scene.video_prompt
  }
}));

const items = $input.all();

return items.map((item, i) => {
  const nextImage = i < items.length - 1 ? items[i + 1].json.scene_image_url : undefined;

  const payload = {
    model: "kwaivgi/kling-v3.0-pro/image-to-video",
    cfg_scale: 0.5,
    duration: item.json.duration_seconds,
    image: item.json.scene_image_url,
    ...(nextImage && { end_image: nextImage }),
    prompt: item.json.video_prompt,
    negative_prompt: "talking, speaking, mouth movement, lip sync, dialogue, voice, speech",
    sound: true
  };

  return {
    json: {
      chunk_number: item.json.chunk_number,
      script: item.json.script,
      body: JSON.stringify(payload)
    }
  };
});

const items = $input.all();

return items.map((item, i) => ({
  json: {
    chunk_number: i + 1,
    video_url: item.json.data.outputs[0]
  }
}));

const items = $input.all();

return items.map((item, i) => ({
  json: {
    chunk_number: i + 1,
    audio_url: item.json.secure_url
  }
}));

const audioItems = $input.all();
const videoItems = $('Extract Video URLs').all();
const chunkItems = $('Split Video Chunks').all();

if (!chunkItems || chunkItems.length === 0) {
  throw new Error('Aucun chunk trouvé depuis "Split Video Chunks".');
}
if (!videoItems || videoItems.length === 0) {
  throw new Error('Aucune vidéo trouvée depuis "Extract Video URLs".');
}
if (!audioItems || audioItems.length === 0) {
  throw new Error('Aucun audio reçu en entrée.');
}

const staticData = $getWorkflowStaticData('global');
const title = staticData.title ?? chunkItems[0]?.json?.title ?? 'Sans titre';

const scenes = chunkItems.map((chunkItem, i) => ({
  chunk_number: chunkItem.json.chunk_number,
  duration_seconds: chunkItem.json.duration_seconds,
  video_url: videoItems[i]?.json?.video_url ?? null,
  audio_url: audioItems[i]?.json?.audio_url ?? null
}));

return [{
  json: {
    title: title,
    scenes: scenes
  }
}];

const data = $input.first().json;

let currentTime = 0;
const videoClips = [];
const audioClips = [];

for (const scene of data.scenes) {
  videoClips.push({
    asset: {
      type: "video",
      src: scene.video_url
    },
    start: currentTime,
    length: "auto"
  });

  audioClips.push({
    asset: {
      type: "audio",
      src: scene.audio_url,
      volume: 1
    },
    start: currentTime,
    length: "auto"
  });

  currentTime += scene.duration_seconds;
}

return [{
  json: {
    body: JSON.stringify({
      timeline: {
        tracks: [
          { clips: videoClips },
          { clips: audioClips }
        ]
      },
      output: {
        format: "mp4",
        resolution: "hd"
      }
    })
  }
}];

const scenes = $('Generate Video Prompts').first().json.output.scenes;

return scenes.map(scene => ({
  json: {
    chunk_number: scene.chunk_number,
    narration: scene.narration,
    body: JSON.stringify({
      text: scene.narration,
      model_id: "eleven_multilingual_v2",
      voice_settings: {
        stability: 0.6,
        similarity_boost: 0.75,
        style: 0.7,
        use_speaker_boost: true
      }
    })
  }
}));

